### Phase 6: App State & Bootstrapping (`lib.rs`)

Open **`app/src-tauri/src/lib.rs`**. This includes `tauri::Manager` to provide `.path()` and `.manage()`, tying everything together safely.

```rust
mod db;
mod secrets;
mod providers;
mod commands;

use std::sync::Mutex;
use tauri::Manager;

pub struct AppState {
    pub db: Mutex<rusqlite::Connection>,
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    tauri::Builder::default()
        .plugin(tauri_plugin_shell::init())
        .setup(|app| {
            let app_data = app.path().app_data_dir()?;
            let db_path = app_data.join("db.sqlite");

            println!("Initializing Local SQLite Database at: {:?}", db_path);
            let conn = db::init_db(db_path).map_err(|e| std::io::Error::new(std::io::ErrorKind::Other, e))?;

            app.manage(AppState { db: Mutex::new(conn) });
            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            commands::save_api_key,
            commands::delete_api_key,
            commands::get_providers_status,
            commands::test_provider_connection,
            commands::save_setting,
            commands::get_setting
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}
```

