```tsx
import "./App.css";
import { useState, useEffect } from "react";
import { invoke } from "@tauri-apps/api/core";

interface ProviderStatus {
  id: string;
  name: string;
  provider_type: string;
  api_url: string;
  has_key: boolean;
  is_local_online: boolean;
}

export default function App() {
  const [activeTab, setActiveTab] = useState<"chat" | "settings">("settings");
  const [providers, setProviders] = useState<ProviderStatus[]>([]);
  const [selectedProvider, setSelectedProvider] = useState<string>("");
  const [apiKeys, setApiKeys] = useState<{ [key: string]: string }>({});
  const [loading, setLoading] = useState<{ [key: string]: boolean }>({});
  const [testResults, setTestResults] = useState<{ [key: string]: { success: boolean; message: string } }>({});

  useEffect(() => {
    loadProviders();
    loadDefaultProvider();
  }, []);

  const loadProviders = async () => {
    try {
      const statusList = await invoke<ProviderStatus[]>("get_providers_status");
      setProviders(statusList);
    } catch (err) {
      console.error("Failed to load providers: ", err);
    }
  };

  const loadDefaultProvider = async () => {
    try {
      const saved = await invoke<string>("get_setting", { key: "default_provider" });
      if (saved) setSelectedProvider(saved);
    } catch (err) {}
  };

  const handleSaveKey = async (providerId: string) => {
    const key = apiKeys[providerId];
    if (!key) return;
    try {
      await invoke("save_api_key", { providerId, apiKey: key });
      setApiKeys((prev) => ({ ...prev, [providerId]: "" }));
      loadProviders();
      alert("API Key saved securely.");
    } catch (err: any) {
      alert("Error saving key: " + err);
    }
  };

  const handleDeleteKey = async (providerId: string) => {
    if (!confirm(`Are you sure you want to remove the API Key for ${providerId}?`)) return;
    try {
      await invoke("delete_api_key", { providerId });
      loadProviders();
      alert("API Key removed.");
    } catch (err: any) {
      alert("Error deleting key: " + err);
    }
  };

  const handleTestConnection = async (providerId: string) => {
    setLoading((prev) => ({ ...prev, [providerId]: true }));
    setTestResults((prev) => {
      const copy = { ...prev };
      delete copy[providerId];
      return copy;
    });

    try {
      const message = await invoke<string>("test_provider_connection", { providerId });
      setTestResults((prev) => ({ ...prev, [providerId]: { success: true, message } }));
    } catch (err: any) {
      setTestResults((prev) => ({ ...prev, [providerId]: { success: false, message: err } }));
    } finally {
      setLoading((prev) => ({ ...prev, [providerId]: false }));
    }
  };

  const handleSelectDefaultProvider = async (id: string) => {
    setSelectedProvider(id);
    await invoke("save_setting", { key: "default_provider", value: id });
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col font-sans">
      <header className="border-b border-slate-800 bg-slate-900/50 px-6 py-4 flex items-center justify-between">
        <h1 className="text-xl font-bold text-indigo-400">Assistant Desktop</h1>
        <nav className="flex space-x-2">
          <button onClick={() => setActiveTab("chat")} className={`px-4 py-2 rounded-lg text-sm font-medium ${activeTab === "chat" ? "bg-indigo-600 text-white" : "text-slate-400"}`}>Chat Interface</button>
          <button onClick={() => setActiveTab("settings")} className={`px-4 py-2 rounded-lg text-sm font-medium ${activeTab === "settings" ? "bg-indigo-600 text-white" : "text-slate-400"}`}>Settings & Providers</button>
        </nav>
      </header>

      <main className="flex-1 p-6 max-w-5xl mx-auto w-full">
        {activeTab === "chat" ? (
          <div className="bg-slate-900 border border-slate-800 rounded-xl p-8 text-center space-y-4">
            <h2 className="text-2xl font-bold">Workspace Chat</h2>
            <div className="bg-slate-950 px-4 py-2 rounded-lg inline-block border border-slate-800 text-slate-300">
              Active Provider Profile: <span className="text-indigo-400 font-semibold uppercase">{selectedProvider}</span>
            </div>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="bg-slate-900 border border-slate-800 rounded-xl p-6">
              <h3 className="text-lg font-semibold mb-4 text-slate-200">Active Shell Engine Target</h3>
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                {providers.map((p) => (
                  <button key={p.id} onClick={() => handleSelectDefaultProvider(p.id)} className={`p-4 rounded-lg border text-left transition-all ${selectedProvider === p.id ? "border-indigo-500 bg-indigo-950/20 shadow-md" : "border-slate-800 bg-slate-950/50 hover:border-slate-700"}`}>
                    <div className="font-semibold text-slate-200">{p.name}</div>
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              {providers.map((p) => (
                <div key={p.id} className="bg-slate-900 border border-slate-800 rounded-xl p-6 flex flex-col md:flex-row gap-6">
                  <div className="space-y-2 max-w-sm">
                    <div className="flex items-center space-x-3">
                      <h4 className="text-lg font-bold text-slate-200">{p.name}</h4>
                      {p.id === "ollama" || p.id === "lmstudio" ? (
                        <span className={`text-xs px-2.5 py-0.5 rounded-full font-semibold ${p.is_local_online ? "bg-emerald-950 text-emerald-400" : "bg-rose-950 text-rose-400"}`}>{p.is_local_online ? "Online" : "Offline / Unreachable"}</span>
                      ) : (
                        <span className={`text-xs px-2.5 py-0.5 rounded-full font-semibold ${p.has_key ? "bg-indigo-950 text-indigo-400" : "bg-slate-850 text-slate-500 border border-slate-800"}`}>{p.has_key ? "Configured" : "No Key Set"}</span>
                      )}
                    </div>
                    <p className="text-sm text-slate-400">Endpoint: <code className="bg-slate-950 px-1 rounded text-indigo-300 text-xs">{p.api_url}</code></p>
                  </div>

                  <div className="flex-1 flex flex-col space-y-3">
                    {p.id !== "ollama" && p.id !== "lmstudio" && (
                      <div className="flex items-center space-x-2">
                        <input type="password" placeholder={p.has_key ? "••••••••••••••••••••" : "Enter API Token"} value={apiKeys[p.id] || ""} onChange={(e) => setApiKeys((prev) => ({ ...prev, [p.id]: e.target.value }))} className="flex-1 bg-slate-950 border border-slate-800 rounded-lg px-3 py-2 text-sm text-slate-200 focus:outline-none focus:border-indigo-500" />
                        <button onClick={() => handleSaveKey(p.id)} className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-lg text-sm font-semibold">Save</button>
                        {p.has_key && <button onClick={() => handleDeleteKey(p.id)} className="px-3 py-2 bg-rose-950 text-rose-300 rounded-lg text-sm font-semibold">Remove</button>}
                      </div>
                    )}
                    <div>
                      <button onClick={() => handleTestConnection(p.id)} disabled={loading[p.id]} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg text-sm font-semibold">{loading[p.id] ? "Executing..." : "Test Endpoint Connection"}</button>
                      {testResults[p.id] && (
                        <div className={`mt-3 p-3 rounded-lg text-xs font-mono border ${testResults[p.id].success ? "bg-emerald-950/20 border-emerald-900/50 text-emerald-300" : "bg-rose-950/20 border-rose-900/50 text-rose-300"}`}>
                          <strong>{testResults[p.id].success ? "SUCCESS" : "ERROR"}:</strong> {testResults[p.id].message}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}
```

