fn get_client_for_url(url: &str, bypass_rules: &[String]) -> Client {
    let mut builder = Client::builder();
    let url_lower = url.to_lowercase();

    // Case-insensitive evaluation of bypass rules
    let should_bypass = bypass_rules.iter().any(|rule| url_lower.contains(&rule.to_lowercase()));
    if should_bypass {
        builder = builder.no_proxy(); 
    }
    builder.build().unwrap_or_else(|_| Client::new())
}

pub async fn ping_url(url: &str) -> bool {
    let client = Client::builder().timeout(Duration::from_secs(1)).no_proxy().build().unwrap_or_default();
    if let Ok(res) = client.get(url).send().await {
        res.status().is_success() || res.status().as_u16() == 404 || res.status().as_u16() == 401
    } else {
        false
    }
}

