}

export const ChatPanel: React.FC<ChatPanelProps> = ({
  messages,
  selectedProvider,
  prompt,
  setPrompt,
  isStreaming,
  isTerminalOpen,
  setIsTerminalOpen,
  onSendMessage,
  editingIndex,
  editingText,
  setEditingText,
  runningCommand,
  onCopy,
  onStartEdit,
  onSaveEdit,
  onCancelEdit,
  onDelete,
  onRerun,
  onRunCommand,
  onWriteFile,
  onOpenPreview,
}) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  return (
